**RF 提高VBANK电压，补偿功率**

// FT烧录的RF电流阈值判断.

\#define RF\_0dBm\_LIMIT (1100\)

struct pa\_lvl\_tag

{

 uint16\_t lvl\_c\_curr;

 uint16\_t lvl\_d\_curr;

 uint16\_t lvl\_e\_curr;

 uint16\_t lvl\_f\_curr;

 uint32\_t ft\_ver;

};

void rf\_patch(void)

{

 struct pa\_lvl\_tag \*p\_pa\_lvl \= (struct pa\_lvl\_tag \*)(0x18000F1C);

 uint8\_t pa\_target \= (p\_pa\_lvl\-\>lvl\_c\_curr \> RF\_0dBm\_LIMIT) ? 0x0C :

 (p\_pa\_lvl\-\>lvl\_d\_curr \> RF\_0dBm\_LIMIT) ? 0x0D :

 (p\_pa\_lvl\-\>lvl\_e\_curr \> RF\_0dBm\_LIMIT) ? 0x0E : 0x0F;

 rf\_pa\_set(pa\_target);

 if ((p\_pa\_lvl\-\>ft\_ver \=\= 0xFFFFFFFF) \|\| (p\_pa\_lvl\-\>ft\_ver \=\= 0x10\))

 {

 uint8\_t bg\_res\_tr \= RF\-\>ANA\_TRIM.BG\_RES\_TRIM;

 bg\_res\_tr \+\= 4;

 if (bg\_res\_tr \> 0x1F)

 bg\_res\_tr \= 0x1F;

 RF\-\>ANA\_TRIM.BG\_RES\_TRIM \= bg\_res\_tr;

 }

